sys_script_include.script:
var UserAccess = Class.create();

UserAccess.prototype = {
  /**
   * Define all variables and roles.
   */
  initialize: function () {
    this.user = gs.getUser();
    this.userRoles = this.user.getRoles();
    this.accessMap = [];
  },
  setUser: function (sys_id) {
    this.userRoles = this.getUserRoles(sys_id);
  },
  getUserRoles: function (sys_id) {
    var grUser = new GlideRecord('sys_user_has_role');
    grUser.addQuery('user', sys_id);

    grUser.query();

    var userRoles = [];

    while (grUser.next()) {
      var role = new GlideRecord('sys_user_role');
      if (role.get(grUser.getValue('role'))) {
        userRoles.push(role.getValue('name'));
      }
    }

    return userRoles;
  },
  setAccessMap: function (accessMap) {
    this.accessMap = accessMap;
    return this;
  },
  isAdmin: function () {
    return this.userRoles.indexOf(Constants.ROLE.ADMIN) >= 0;
  },
  isBusinessOwner: function () {
    return this.userRoles.indexOf(Constants.ROLE.BUSINESS_OWNER) >= 0;
  },
  isSubscriber: function () {
    return this.userRoles.indexOf(Constants.ROLE.SUBSCRIBER) >= 0;
  },
  isUser: function () {
    return this.userRoles.indexOf(Constants.ROLE.USER) >= 0;
  },
  isExactlyBusinessOwner: function () {
    return !this.isAdmin() && this.isBusinessOwner();
  },
  isExactlySubscriber: function () {
    return !this.isAdmin() && !this.isBusinessOwner() && this.isSubscriber();
  },
  isOwner: function (userId) {
    return this.user.getID() == userId;
  },
  hasAccess: function (table, action, paramObject) {
    if (!this.accessMap[table][action]) {
      return false;
    }

    var role, rule, roleId;
    var roles = this.userRoles.slice();
    roles.unshift(Constants.ROLE.ANY);

    for (roleId in roles) {
      role = roles[roleId];
      rule = this.accessMap[table][action][role];

      if (!rule) {
        continue;
      }

      if (rule === true) {
        return true;
      }

      if (typeof rule === 'function' && rule(this.user, paramObject)) {
        return true;
      }
    }

    return false;
  },
  type: 'UserAccess',
};
